SELECT baseline."in.comstock_building_type" AS comstock_building_type, sum(1) AS sample_count, sum(baseline.weight) AS units_count, sum(baseline."out.electricity.total.energy_consumption..kwh" * baseline.weight) AS "electricity.total.energy_consumption..kwh__baseline", sum(upgrade."out.electricity.total.energy_consumption..kwh" * baseline.weight) AS "electricity.total.energy_consumption..kwh__upgrade", sum((coalesce(baseline."out.electricity.total.energy_consumption..kwh", 0) - coalesce(upgrade."out.electricity.total.energy_consumption..kwh", 0)) * baseline.weight) AS "electricity.total.energy_consumption..kwh__savings", approx_percentile(baseline."out.electricity.total.energy_consumption..kwh", ARRAY[0, 0.02, 0.1, 0.25, 0.5, 0.75, 0.9, 0.98, 1]) AS "electricity.total.energy_consumption..kwh__baseline__quartiles", approx_percentile(baseline."out.electricity.total.energy_consumption..kwh", ARRAY[0, 0.02, 0.1, 0.25, 0.5, 0.75, 0.9, 0.98, 1]) FILTER (WHERE baseline."out.electricity.total.energy_consumption..kwh" != 0) AS "electricity.total.energy_consumption..kwh__baseline__nonzero_quartiles", approx_percentile(upgrade."out.electricity.total.energy_consumption..kwh", ARRAY[0, 0.02, 0.1, 0.25, 0.5, 0.75, 0.9, 0.98, 1]) AS "electricity.total.energy_consumption..kwh__upgrade__quartiles", approx_percentile(upgrade."out.electricity.total.energy_consumption..kwh", ARRAY[0, 0.02, 0.1, 0.25, 0.5, 0.75, 0.9, 0.98, 1]) FILTER (WHERE upgrade."out.electricity.total.energy_consumption..kwh" != 0) AS "electricity.total.energy_consumption..kwh__upgrade__nonzero_quartiles", approx_percentile(coalesce(baseline."out.electricity.total.energy_consumption..kwh", 0) - coalesce(upgrade."out.electricity.total.energy_consumption..kwh", 0), ARRAY[0, 0.02, 0.1, 0.25, 0.5, 0.75, 0.9, 0.98, 1]) AS "electricity.total.energy_consumption..kwh__savings__quartiles", approx_percentile(coalesce(baseline."out.electricity.total.energy_consumption..kwh", 0) - coalesce(upgrade."out.electricity.total.energy_consumption..kwh", 0), ARRAY[0, 0.02, 0.1, 0.25, 0.5, 0.75, 0.9, 0.98, 1]) FILTER (WHERE coalesce(baseline."out.electricity.total.energy_consumption..kwh", 0) - coalesce(upgrade."out.electricity.total.energy_consumption..kwh", 0) != 0) AS "electricity.total.energy_consumption..kwh__savings__nonzero_quartiles" 
FROM (SELECT * 
FROM comstock_amy2018_r2_2025_md_by_state_and_county_parquet 
WHERE comstock_amy2018_r2_2025_md_by_state_and_county_parquet.upgrade = 0) AS baseline JOIN (SELECT * 
FROM comstock_amy2018_r2_2025_md_by_state_and_county_parquet 
WHERE comstock_amy2018_r2_2025_md_by_state_and_county_parquet.upgrade != 0) AS upgrade ON baseline.bldg_id = upgrade.bldg_id AND baseline."in.nhgis_tract_gisjoin" = upgrade."in.nhgis_tract_gisjoin" AND baseline.state = upgrade.state AND upgrade.upgrade = 1 AND upgrade.applicability = true 
WHERE baseline.applicability = true AND baseline.state = 'CO' GROUP BY 1 ORDER BY 1